import React from 'react';
import axios from 'axios';

function NoteList({ notes, fetchNotes }) {
  const deleteNote = async (id) => {
    try {
      await axios.delete(`http://localhost:5001/api/notes/${id}`);
      fetchNotes();
    } catch (err) { console.error(err); }
  };

  // Styles defined as objects for clean JSX
  const styles = {
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '2rem',
      padding: '2rem',
      background: '#f8fafc', // Ultra-light cool gray background
      minHeight: '100vh',
    },
    card: {
      position: 'relative',
      background: '#ffffff',
      borderRadius: '20px',
      padding: '24px',
      border: '1px solid rgba(226, 232, 240, 0.8)',
      boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.04), 0 4px 6px -2px rgba(0, 0, 0, 0.02)',
      transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
      display: 'flex',
      flexDirection: 'column',
    },
    categoryTag: {
      fontSize: '11px',
      textTransform: 'uppercase',
      letterSpacing: '0.05em',
      fontWeight: '700',
      color: '#6366f1', // Indigo accent
      marginBottom: '12px',
    },
    title: {
      fontSize: '1.25rem',
      fontWeight: '700',
      color: '#1e293b',
      marginBottom: '10px',
      lineHeight: '1.3',
    },
    content: {
      fontSize: '0.95rem',
      color: '#64748b',
      lineHeight: '1.6',
      marginBottom: '24px',
      flexGrow: 1,
    },
    deleteBtn: {
      cursor: 'pointer',
      padding: '10px 16px',
      borderRadius: '12px',
      border: 'none',
      backgroundColor: '#fff1f2',
      color: '#e11d48',
      fontSize: '0.85rem',
      fontWeight: '600',
      transition: 'all 0.2s ease',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
      width: 'fit-content'
    }
  };

  return (
    <div style={styles.grid}>
      {notes.map(note => (
        <div 
          key={note._id} 
          style={styles.card}
          className="note-card"
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-8px)';
            e.currentTarget.style.boxShadow = '0 20px 25px -5px rgba(0, 0, 0, 0.1)';
            e.currentTarget.style.borderColor = '#6366f1';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = styles.card.boxShadow;
            e.currentTarget.style.borderColor = 'rgba(226, 232, 240, 0.8)';
          }}
        >
          <span style={styles.categoryTag}>Personal Note</span>
          <h3 style={styles.title}>{note.title}</h3>
          <p style={styles.content}>{note.content}</p>

          <button 
            style={styles.deleteBtn}
            onClick={() => deleteNote(note._id)}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = '#ffe4e6';
              e.currentTarget.style.transform = 'scale(1.05)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = '#fff1f2';
              e.currentTarget.style.transform = 'scale(1)';
            }}
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2" />
            </svg>
            Delete
          </button>
        </div>
      ))}
    </div>
  );
}

export default NoteList;
